"use strict";(globalThis.webpackChunktemp_website=globalThis.webpackChunktemp_website||[]).push([[856],{7024(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/ocp-wiki/","label":"\ud83d\ude80 Introduction","docId":"intro","unlisted":false},{"type":"link","href":"/ocp-wiki/history","label":"\ud83d\udcdc History","docId":"history","unlisted":false},{"type":"category","label":"\ud83c\udfd7\ufe0fProtocol Architecture","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/ocp-wiki/architecture/overview","label":"\ud83d\uddfa\ufe0fArchitecture Overview","docId":"architecture/overview","unlisted":false},{"type":"link","href":"/ocp-wiki/architecture/layer-1-discovery","label":"\ud83c\udf10 Layer 1: Discovery","docId":"architecture/layer-1-discovery","unlisted":false},{"type":"link","href":"/ocp-wiki/architecture/layer-2-identity","label":"\ud83c\udd94 Layer 2: Identity","docId":"architecture/layer-2-identity","unlisted":false},{"type":"link","href":"/ocp-wiki/architecture/layer-3-knowledge","label":"\ud83e\udde0 Layer 3: Knowledge","docId":"architecture/layer-3-knowledge","unlisted":false},{"type":"link","href":"/ocp-wiki/architecture/layer-4-collaboration","label":"\ud83d\udc1d Layer 4: Collaboration","docId":"architecture/layer-4-collaboration","unlisted":false},{"type":"link","href":"/ocp-wiki/architecture/layer-5-application","label":"\ud83e\udde9 Layer 5: Application","docId":"architecture/layer-5-application","unlisted":false},{"type":"link","href":"/ocp-wiki/architecture/message-format","label":"\ud83d\udcc4 Message Format","docId":"architecture/message-format","unlisted":false}],"href":"/ocp-wiki/category/\ufe0fprotocol-architecture"},{"type":"category","label":"\ud83d\udee1\ufe0fSecurity & Resilience","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/ocp-wiki/security/","label":"\ud83e\uddef  Threat & Recovery","docId":"security/security","unlisted":false}],"href":"/ocp-wiki/category/\ufe0fsecurity--resilience"},{"type":"link","href":"/ocp-wiki/governance","label":"\ud83c\udfdb\ufe0fGovernance","docId":"governance","unlisted":false},{"type":"link","href":"/ocp-wiki/reference_implementation","label":"\ud83e\uddf1 Reference Implementation","docId":"reference_implementation","unlisted":false},{"type":"link","href":"/ocp-wiki/comparison","label":"\u2696\ufe0f Comparison","docId":"comparison","unlisted":false},{"type":"link","href":"/ocp-wiki/use-cases","label":"\ud83d\udca1 Use Cases","docId":"use-cases","unlisted":false},{"type":"link","href":"/ocp-wiki/references","label":"\ud83d\udcda References","docId":"references","unlisted":false}]},"docs":{"architecture/layer-1-discovery":{"id":"architecture/layer-1-discovery","title":"Layer 1: Network & Discovery","description":"The base layer handles message delivery and agent discovery. OCP supports four transport mechanisms: WebSocket (recommended for real-time bidirectional communication), HTTPS (for request-response patterns), NATS (for high-throughput publish-subscribe), and gRPC (for low-latency remote procedure calls). All transports require TLS 1.3 or higher.","sidebar":"tutorialSidebar"},"architecture/layer-2-identity":{"id":"architecture/layer-2-identity","title":"Layer 2: Identity & Trust","description":"Every OCP agent is identified by a Decentralized Identifier (DID) that conforms to the W3C DID Core specification and uses the ocp DID method. The agent identifier is derived from the SHA-3-256 hash of the agent\'s Ed25519 public key. Each agent publishes a DID Document containing its public key, service endpoint, capability declarations, and trust attestations.","sidebar":"tutorialSidebar"},"architecture/layer-3-knowledge":{"id":"architecture/layer-3-knowledge","title":"Layer 3: Knowledge Exchange","description":"The knowledge layer defines three types of shareable information:","sidebar":"tutorialSidebar"},"architecture/layer-4-collaboration":{"id":"architecture/layer-4-collaboration","title":"Layer 4: Agent Collaboration","description":"The collaboration layer enables task delegation and multi-agent consensus.","sidebar":"tutorialSidebar"},"architecture/layer-5-application":{"id":"architecture/layer-5-application","title":"Layer 5: Application & API","description":"The application layer is not specified by OCP itself. It represents domain-specific AI applications, products, and agents that build on the lower four layers. Domain-specific extensions (such as ocp-extdicom-sharefinancev1) can be registered in the OCP Extension Registry and layered on top of the core protocol.","sidebar":"tutorialSidebar"},"architecture/message-format":{"id":"architecture/message-format","title":"Message Format","description":"All OCP communication uses the OCP Universal Message Format (OCPUMF), a JSON-based envelope containing the protocol version, a unique message identifier, a UTC timestamp, a time-to-live value, sender and receiver identifiers with cryptographic signatures, a message type, priority level, optional encryption parameters, an arbitrary payload, and metadata including tags, language, acknowledgment requirements, and correlation and trace identifiers.","sidebar":"tutorialSidebar"},"architecture/overview":{"id":"architecture/overview","title":"Protocol Architecture Overview","description":"The OpenCognition Protocol (OCP) is structured as a 5-Layer Stack. Only the bottom two layers are required for a conforming implementation; the upper three layers are optional and may be adopted incrementally. This modular design ensures that each component from raw networking to high-level application logic can evolve independently while maintaining a secure and reliable framework for cognitive interoperability.","sidebar":"tutorialSidebar"},"comparison":{"id":"comparison","title":"\u2696\ufe0f Competitive Landscape","description":"The OpenCognition Protocol (OCP) occupies a unique position in the ecosystem, bridging the gap between raw communication and high-level AI orchestration.","sidebar":"tutorialSidebar"},"governance":{"id":"governance","title":"Governance","description":"OCP is governed by a proposed community foundation comprising four bodies:","sidebar":"tutorialSidebar"},"history":{"id":"history","title":"History of the OpenCognition Protocol","description":"---","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"OpenCognition Protocol","description":"Summary","sidebar":"tutorialSidebar"},"reference_implementation":{"id":"reference_implementation","title":"Reference Implementation","description":"The OCP reference implementation is released on GitHub under the MIT license and includes:","sidebar":"tutorialSidebar"},"references":{"id":"references","title":"References","description":"1.\\tW3C. \\"Decentralized Identifiers (DIDs) v1.0.\\" W3C Recommendation, 2022.","sidebar":"tutorialSidebar"},"security/security":{"id":"security/security","title":"Security","description":"Cryptographic Primitives","sidebar":"tutorialSidebar"},"use-cases":{"id":"use-cases","title":"Use Cases","description":"Healthcare. A hospital\'s diagnostic AI identifies a rare imaging pattern associated with early-stage disease. Through OCP, it shares an anonymized insight package with peer systems at other institutions. Receiving agents incorporate the pattern into their own detection workflows without any patient data changing hands.","sidebar":"tutorialSidebar"}}}}')}}]);